class Solution {
    public int possibleStringCount(String word, int k) {
        long count = 1;
        int mod = 1000000007;
        for (int i = 0; i < word.length(); i++) {
            int freq = 1;
            for (int j = i + 1; j < word.length() && j < i + k; j++) {
                if (word.charAt(j) == word.charAt(i)) {
                    freq++;
                }
            }
            count = (count * freq) % mod;
        }
        return (int) count;
    }
}
